const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });
function project(balance: number, monthly: number, matchPct: number, annualReturn: number, years: number) {
  const r = annualReturn / 100 / 12;
  const match = monthly * matchPct / 100;
  let value = balance;
  let contributed = 0;
  let matched = 0;
  for (let i = 0; i < years * 12; i += 1) { value = value * (1 + r) + monthly + match; contributed += monthly; matched += match; }
  return { value, contributed, matched, monthlyIncome: value * 0.04 / 12 };
}
